const item = $input.first().json;
const emailBody = item.snippet || '';
const subject = item.Subject || '';
const sender = item.From || '';

// Strip HTML
let cleanBody = emailBody.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

// Prompt injection protection
const injectionPatterns = [
  /ignore (all |any )?(previous |prior |above )?instructions/gi,
  /you are now/gi,
  /new instructions:/gi,
  /system prompt/gi,
  /\[INST\]/gi,
  /<\|im_start\|>/gi,
  /```(system|assistant)/gi,
  /forget (all |any )?(previous |prior )?/gi,
  /disregard/gi,
  /override/gi
];

for (const pattern of injectionPatterns) {
  cleanBody = cleanBody.replace(pattern, '[BLOCKED]');
}

// Truncate
cleanBody = cleanBody.substring(0, 4000);

return [{
  json: {
    body: cleanBody,
    subject: subject.substring(0, 200),
    from: sender.substring(0, 200)
  }
}];

const sanitized = $('Sanitize Input').item.json;
const skillResponse = $('Fetch IB Skill').item.json;

// Extract skill content — handle both string and object responses
let skillContent = '';
if (typeof skillResponse === 'string') {
  skillContent = skillResponse;
} else if (skillResponse.data) {
  skillContent = skillResponse.data;
} else if (skillResponse.body) {
  skillContent = skillResponse.body;
} else {
  skillContent = JSON.stringify(skillResponse);
}

return [{
  json: {
    body: sanitized.body,
    subject: sanitized.subject,
    from: sanitized.from,
    skill: skillContent
  }
}];

const agentOutput = $input.first().json.output;
const emailData = $('Merge Skill + Email').item.json;

// Parse JSON
let jsonStr = agentOutput;
if (jsonStr.includes('```')) {
  jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
}

let data;
try {
  data = JSON.parse(jsonStr);
} catch(e) {
  const match = jsonStr.match(/\{[\s\S]*\}/);
  if (match) data = JSON.parse(match[0]);
  else throw new Error('Failed to parse agent JSON: ' + e.message);
}

const companies = data.companies || [];
const sectorOverview = data.sector_overview || '';
const comparativeAnalysis = data.comparative_analysis || '';
const keyThemes = data.key_themes || [];
const dateStr = new Date().toISOString().split('T')[0];

// === HTML REPORT ===
let html = `<html><head><style>
  body{font-family:Georgia,'Times New Roman',serif;max-width:960px;margin:0 auto;padding:30px;color:#1a1a1a;line-height:1.6}
  h1{color:#003366;border-bottom:3px solid #003366;padding-bottom:12px;font-size:26px}
  h2{color:#003366;margin-top:35px;border-bottom:2px solid #ccc;padding-bottom:8px;font-size:20px}
  h3{color:#1a5276;font-size:16px}
  h4{color:#2c3e50;font-size:14px;margin-bottom:4px}
  .conf{color:#c62828;font-weight:bold;text-align:center;font-size:11px;text-transform:uppercase;letter-spacing:2px;margin-bottom:20px}
  .mg{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin:12px 0}
  .mb{background:#f7f9fc;padding:10px;border-radius:4px;border:1px solid #dce4ec;text-align:center}
  .ml{font-size:10px;color:#666;text-transform:uppercase;letter-spacing:.5px}
  .mv{font-size:16px;font-weight:bold;color:#003366;margin-top:2px}
  table{width:100%;border-collapse:collapse;margin:12px 0;font-size:12px}
  th{background:#003366;color:white;padding:8px 6px;text-align:left;font-weight:600}
  td{padding:7px 6px;border-bottom:1px solid #e0e0e0}
  tr:nth-child(even){background:#f8f9fa}
  .swot{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:12px 0}
  .sb{padding:12px;border-radius:6px;font-size:12px}
  .ss{background:#e8f5e9;border-left:4px solid #2e7d32}
  .sw{background:#fce4ec;border-left:4px solid #c62828}
  .so{background:#e3f2fd;border-left:4px solid #1565c0}
  .st{background:#fff3e0;border-left:4px solid #e65100}
  .dcf{background:#f3e5f5;padding:14px;border-radius:6px;border-left:4px solid #7b1fa2;margin:12px 0}
  .ma{background:#fff8e1;padding:14px;border-radius:6px;border-left:4px solid #f9a825;margin:12px 0}
  .th{display:inline-block;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;margin:2px}
  .bull{background:#e8f5e9;border-left:4px solid #2e7d32;padding:10px;border-radius:4px;margin:6px 0}
  .base{background:#e3f2fd;border-left:4px solid #1565c0;padding:10px;border-radius:4px;margin:6px 0}
  .bear{background:#fce4ec;border-left:4px solid #c62828;padding:10px;border-radius:4px;margin:6px 0}
  .risk{background:#fff5f5;padding:14px;border-radius:6px;margin:12px 0}
  .cat{background:#e0f2f1;padding:6px 12px;margin:4px 0;border-radius:4px;border-left:3px solid #00897b;font-size:12px}
  .moat{display:inline-block;padding:3px 10px;border-radius:10px;font-size:11px;font-weight:bold}
  .mw{background:#2e7d32;color:white}.mn{background:#f9a825;color:#333}.mno{background:#e0e0e0;color:#666}
  .ob{background:#e8eaf6;padding:16px;border-radius:8px;margin:18px 0}
  .tags{display:flex;gap:8px;flex-wrap:wrap;margin:10px 0}
  .tag{background:#003366;color:white;padding:5px 12px;border-radius:14px;font-size:12px}
  .disc{background:#f5f5f5;padding:14px;border-radius:6px;font-size:11px;color:#888;margin-top:40px;border:1px solid #e0e0e0}
  ul{padding-left:18px;margin:5px 0}li{margin:3px 0;font-size:12px}
</style></head><body>`;

html += `<div class="conf">Confidential — For Internal Use Only</div>`;
html += `<h1>Investment Banking Research Report</h1>`;
html += `<p><em>Generated ${dateStr} | ${companies.length} ${companies.length === 1 ? 'company' : 'companies'} analyzed</em></p>`;

if (keyThemes.length) html += `<div class="tags">${keyThemes.map(t=>`<span class="tag">${t}</span>`).join('')}</div>`;
if (sectorOverview) html += `<div class="ob"><h3>Sector Overview</h3><p>${sectorOverview}</p></div>`;

for (const c of companies) {
  const mc = (c.competitive_moat||'').toLowerCase();
  const moatCls = mc.includes('wide')?'mw':mc.includes('narrow')?'mn':'mno';

  html += `<h2>${c.name} (${c.ticker||'N/A'}) <span class="moat ${moatCls}">${c.competitive_moat||'N/A'} moat</span></h2>`;
  html += `<p><strong>${c.sector||''}</strong> | ${c.industry||''} | ${c.exchange||''} | ${c.headquarters||''}</p>`;
  html += `<p>${c.business_description||''}</p>`;
  if (c.revenue_segments) html += `<p><strong>Segments:</strong> ${c.revenue_segments}</p>`;
  if (c.strategic_narrative) html += `<p><strong>Strategic Focus:</strong> ${c.strategic_narrative}</p>`;

  // Metrics grid
  const metrics = [
    ['Market Cap',c.market_cap],['EV',c.enterprise_value],['Revenue LTM',c.revenue_ltm],['Rev Growth',c.revenue_growth_yoy],
    ['Gross Margin',c.gross_margin],['EBITDA',c.ebitda],['EBITDA Margin',c.ebitda_margin],['Net Income',c.net_income],
    ['EPS',c.eps],['FCF',c.fcf],['FCF Yield',c.fcf_yield],['Net Debt',c.net_debt],
    ['Debt/EBITDA',c.net_debt_to_ebitda],['Int. Coverage',c.interest_coverage],['ROE',c.roe],['ROIC',c.roic],
    ['P/E',c.pe_ratio],['EV/EBITDA',c.ev_ebitda],['EV/Revenue',c.ev_revenue],['P/B',c.pb_ratio],
    ['Div Yield',c.dividend_yield],['52W High',c['52w_high']],['52W Low',c['52w_low']]
  ];
  html += `<h3>Financial Summary</h3><div class="mg">`;
  for (const [l,v] of metrics) { if(v) html += `<div class="mb"><div class="ml">${l}</div><div class="mv">${v}</div></div>`; }
  html += `</div>`;

  // Comps
  if (c.comps?.length) {
    html += `<h3>Comparable Companies</h3>`;
    if (c.peer_selection_rationale) html += `<p><em>${c.peer_selection_rationale}</em></p>`;
    html += `<table><tr><th>Company</th><th>Ticker</th><th>Mkt Cap</th><th>EV/Rev</th><th>EV/EBITDA</th><th>P/E</th><th>Rev Growth</th><th>EBITDA Margin</th><th>Debt/EBITDA</th></tr>`;
    for (const p of c.comps) html += `<tr><td>${p.name}</td><td>${p.ticker}</td><td>${p.market_cap}</td><td>${p.ev_revenue}</td><td>${p.ev_ebitda}</td><td>${p.pe}</td><td>${p.rev_growth}</td><td>${p.ebitda_margin}</td><td>${p.net_debt_ebitda||'-'}</td></tr>`;
    if (c.comps_median) html += `<tr style="font-weight:bold;background:#e8eaf6"><td colspan="3">Median</td><td>${c.comps_median.ev_revenue}</td><td>${c.comps_median.ev_ebitda}</td><td>${c.comps_median.pe}</td><td colspan="3"></td></tr>`;
    html += `</table>`;
  }

  // Valuation
  const vc1 = c.valuation_comps_ev_ebitda;
  const vc2 = c.valuation_comps_ev_revenue;
  const dcf = c.dcf_indicators;
  const pt = c.precedent_transactions;
  if (vc1 || vc2 || dcf || pt?.length) {
    html += `<h3>Valuation</h3><table><tr><th>Methodology</th><th>Low</th><th>Mid</th><th>High</th></tr>`;
    if (vc1) html += `<tr><td>Comps (EV/EBITDA)</td><td>${vc1.low}</td><td>${vc1.mid}</td><td>${vc1.high}</td></tr>`;
    if (vc2) html += `<tr><td>Comps (EV/Revenue)</td><td>${vc2.low}</td><td>${vc2.mid}</td><td>${vc2.high}</td></tr>`;
    if (dcf) html += `<tr><td>DCF (indicative)</td><td>${dcf.implied_low}</td><td>${dcf.implied_mid}</td><td>${dcf.implied_high}</td></tr>`;
    html += `</table>`;
    if (dcf) html += `<div class="dcf"><strong>WACC:</strong> ${dcf.wacc_range} | <strong>Terminal Growth:</strong> ${dcf.terminal_growth}<br><em>${dcf.note||''}</em></div>`;
  }
  if (pt?.length) {
    html += `<h4>Precedent Transactions</h4><table><tr><th>Target</th><th>Acquirer</th><th>EV/EBITDA</th><th>EV/Revenue</th><th>Premium</th><th>Year</th></tr>`;
    for (const t of pt) html += `<tr><td>${t.target}</td><td>${t.acquirer}</td><td>${t.ev_ebitda}</td><td>${t.ev_revenue}</td><td>${t.premium||'-'}</td><td>${t.year}</td></tr>`;
    html += `</table>`;
  }

  // M&A
  if (c.ma_recent_deals?.length || c.ma_potential_acquirers?.length) {
    html += `<div class="ma"><h3>M&A Context</h3>`;
    if (c.ma_recent_deals?.length) html += `<h4>Recent Deals</h4><ul>${c.ma_recent_deals.map(d=>`<li>${d}</li>`).join('')}</ul>`;
    if (c.ma_potential_acquirers?.length) html += `<h4>Potential Acquirers</h4><ul>${c.ma_potential_acquirers.map(d=>`<li>${d}</li>`).join('')}</ul>`;
    if (c.ma_potential_targets?.length) html += `<h4>Bolt-on Targets</h4><ul>${c.ma_potential_targets.map(d=>`<li>${d}</li>`).join('')}</ul>`;
    if (c.ma_activist_potential) html += `<p><strong>Activist Potential:</strong> ${c.ma_activist_potential}</p>`;
    html += `</div>`;
  }

  // SWOT
  html += `<h3>SWOT Analysis</h3><div class="swot">`;
  html += `<div class="sb ss"><strong>Strengths</strong><ul>${(c.strengths||[]).map(s=>`<li>${s}</li>`).join('')}</ul></div>`;
  html += `<div class="sb sw"><strong>Weaknesses</strong><ul>${(c.weaknesses||[]).map(s=>`<li>${s}</li>`).join('')}</ul></div>`;
  html += `<div class="sb so"><strong>Opportunities</strong><ul>${(c.opportunities||[]).map(s=>`<li>${s}</li>`).join('')}</ul></div>`;
  html += `<div class="sb st"><strong>Threats</strong><ul>${(c.threats||[]).map(s=>`<li>${s}</li>`).join('')}</ul></div>`;
  html += `</div>`;
  if (c.moat_reasoning) html += `<p><strong>Moat Reasoning:</strong> ${c.moat_reasoning}</p>`;

  // Risks
  const hasRisks = c.risks_company?.length || c.risks_industry?.length || c.risks_regulatory?.length;
  if (hasRisks) {
    html += `<div class="risk"><h3>Risk Factors</h3>`;
    if (c.risks_company?.length) html += `<h4>Company-Specific</h4><ul>${c.risks_company.map(r=>`<li>${r}</li>`).join('')}</ul>`;
    if (c.risks_industry?.length) html += `<h4>Industry/Macro</h4><ul>${c.risks_industry.map(r=>`<li>${r}</li>`).join('')}</ul>`;
    if (c.risks_regulatory?.length) html += `<h4>Regulatory</h4><ul>${c.risks_regulatory.map(r=>`<li>${r}</li>`).join('')}</ul>`;
    if (c.risks_esg?.length) html += `<h4>ESG</h4><ul>${c.risks_esg.map(r=>`<li>${r}</li>`).join('')}</ul>`;
    html += `</div>`;
  }

  // Catalysts
  if (c.catalysts?.length) {
    html += `<h3>Catalysts</h3>`;
    for (const cat of c.catalysts) html += `<div class="cat">${cat}</div>`;
  }

  // Thesis
  html += `<h3>Investment Thesis</h3>`;
  if (c.thesis_bull) html += `<div class="bull"><strong>Bull:</strong> ${c.thesis_bull}</div>`;
  if (c.thesis_base) html += `<div class="base"><strong>Base:</strong> ${c.thesis_base}</div>`;
  if (c.thesis_bear) html += `<div class="bear"><strong>Bear:</strong> ${c.thesis_bear}</div>`;
  html += `<hr>`;
}

if (comparativeAnalysis) html += `<div class="ob"><h3>Comparative Analysis</h3><p>${comparativeAnalysis}</p></div>`;

html += `<div class="disc"><strong>Disclaimer:</strong> AI-generated research for informational purposes only. Not investment advice. Financial data may include estimates. Verify all figures against primary sources (SEC filings, Bloomberg, FactSet) before use in client-facing materials or investment decisions.</div>`;
html += `</body></html>`;

// === CSV ===
const csvFields = ['Company','Ticker','Exchange','Sector','Industry','HQ','Market Cap','EV','Revenue LTM','Rev Growth','Gross Margin','EBITDA','EBITDA Margin','Net Income','EPS','Total Debt','Net Debt','Cash','FCF','FCF Yield','Debt/EBITDA','Interest Coverage','ROE','ROIC','P/E','EV/EBITDA','EV/Revenue','P/B','Div Yield','52W High','52W Low','Moat','Bull Case','Base Case','Bear Case'];
const csvKeys = ['name','ticker','exchange','sector','industry','headquarters','market_cap','enterprise_value','revenue_ltm','revenue_growth_yoy','gross_margin','ebitda','ebitda_margin','net_income','eps','total_debt','net_debt','cash','fcf','fcf_yield','net_debt_to_ebitda','interest_coverage','roe','roic','pe_ratio','ev_ebitda','ev_revenue','pb_ratio','dividend_yield','52w_high','52w_low','competitive_moat','thesis_bull','thesis_base','thesis_bear'];

let csv = csvFields.join(',') + '\n';
for (const c of companies) {
  csv += csvKeys.map(k => '"' + String(c[k]||'').replace(/"/g,'""') + '"').join(',') + '\n';
}

// Comps sheet
if (companies.some(c => c.comps?.length)) {
  csv += '\n\nCOMPARABLE COMPANIES\n';
  csv += 'Target,Peer,Ticker,Mkt Cap,EV/Revenue,EV/EBITDA,P/E,Rev Growth,EBITDA Margin,Debt/EBITDA\n';
  for (const c of companies) {
    for (const p of (c.comps||[])) {
      csv += `"${c.name}","${p.name}","${p.ticker}","${p.market_cap}","${p.ev_revenue}","${p.ev_ebitda}","${p.pe}","${p.rev_growth}","${p.ebitda_margin}","${p.net_debt_ebitda||''}"\n`;
    }
  }
}

// Precedent transactions sheet
if (companies.some(c => c.precedent_transactions?.length)) {
  csv += '\n\nPRECEDENT TRANSACTIONS\n';
  csv += 'Related To,Target,Acquirer,EV/EBITDA,EV/Revenue,Premium,Year\n';
  for (const c of companies) {
    for (const t of (c.precedent_transactions||[])) {
      csv += `"${c.name}","${t.target}","${t.acquirer}","${t.ev_ebitda}","${t.ev_revenue}","${t.premium||''}","${t.year}"\n`;
    }
  }
}

const csvBuf = Buffer.from(csv, 'utf-8');

return [{
  json: {
    htmlReport: html,
    from: emailData.from,
    subject: emailData.subject
  },
  binary: {
    data: {
      data: csvBuf.toString('base64'),
      mimeType: 'text/csv',
      fileName: 'ib_research_' + dateStr + '.csv',
      fileExtension: 'csv'
    }
  }
}];
